@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (loading)
{
    <div class="text-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
        <p class="mt-2 text-muted">Loading tasks…</p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Total="allTasks.Count"
                TodoCount="todoTasks.Count"
                InProgressCount="inProgressTasks.Count"
                DoneCount="doneTasks.Count"
                OverdueCount="overdueTasks.Count" />

    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="filteredTodo"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveRight="id => MoveTask(id, \"In Progress\")"
                     OnAddTask="data => AddTask(data, \"To Do\")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="filteredInProgress"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveLeft="id => MoveTask(id, \"To Do\")"
                     OnMoveRight="id => MoveTask(id, \"Done\")"
                     OnAddTask="data => AddTask(data, \"In Progress\")" />

        <BoardColumn ColumnName="Done"
                     Tasks="filteredDone"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveLeft="id => MoveTask(id, \"In Progress\")"
                     OnAddTask="data => AddTask(data, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private bool loading = true;
    private string? errorMessage;

    private string searchText = string.Empty;

    // Unfiltered lists by status (used for stats)
    private List<TaskItem> todoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private List<TaskItem> overdueTasks => allTasks.Where(t => t.DueDate < DateTime.Today).ToList();

    // Filtered lists (search applied)
    private List<TaskItem> filteredTodo => Filter(todoTasks);
    private List<TaskItem> filteredInProgress => Filter(inProgressTasks);
    private List<TaskItem> filteredDone => Filter(doneTasks);

    private List<TaskItem> Filter(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;

        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

